import{_ as t,c as o,o as s,ag as r}from"./chunks/framework.Bw-5EFTY.js";const g=JSON.parse('{"title":"Sessions Specification","description":"","frontmatter":{},"headers":[],"relativePath":"packages/agent-sessions/SPEC.md","filePath":"packages/agent-sessions/SPEC.md"}'),d={name:"packages/agent-sessions/SPEC.md"};function n(a,e,i,c,l,p){return s(),o("div",null,e[0]||(e[0]=[r(`<h1 id="sessions-specification" tabindex="-1">Sessions Specification <a class="header-anchor" href="#sessions-specification" aria-label="Permalink to &quot;Sessions Specification&quot;">​</a></h1><h2 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h2><p>Owns the CLI session lifecycle for the Robota SDK. This package provides the <code>Session</code> class that wraps a <code>Robota</code> agent instance with permission-gated tool execution, hook-based lifecycle events, context window tracking, conversation compaction, and optional JSON file persistence via <code>SessionStore</code>. It is the primary runtime used by the CLI application (<code>agent-cli</code>) via the assembly layer (<code>agent-sdk</code>).</p><h2 id="boundaries" tabindex="-1">Boundaries <a class="header-anchor" href="#boundaries" aria-label="Permalink to &quot;Boundaries&quot;">​</a></h2><ul><li>Does not own AI provider creation. Accepts a pre-constructed <code>IAIProvider</code> via injection.</li><li>Does not own tool implementations. Accepts pre-constructed <code>IToolWithEventService[]</code> via injection.</li><li>Does not own system prompt building. Accepts a pre-built <code>systemMessage</code> string.</li><li>Does not own configuration resolution or context loading. Those belong to <code>agent-sdk</code>.</li><li>Does not own the permission evaluation algorithm or hook execution engine. Those belong to <code>@robota-sdk/agent-core</code> (<code>evaluatePermission</code>, <code>runHooks</code>).</li></ul><h2 id="architecture-overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to &quot;Architecture Overview&quot;">​</a></h2><p>The package follows a modular structure with Session delegating to focused sub-components:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>session.ts                -- Session class: orchestrates run loop, delegates to sub-components</span></span>
<span class="line"><span>permission-enforcer.ts    -- PermissionEnforcer: tool wrapping, permission checks, hooks, truncation</span></span>
<span class="line"><span>context-window-tracker.ts -- ContextWindowTracker: token usage tracking, auto-compact threshold</span></span>
<span class="line"><span>compaction-orchestrator.ts -- CompactionOrchestrator: conversation summarization via LLM</span></span>
<span class="line"><span>session-logger.ts         -- ISessionLogger interface + FileSessionLogger / SilentSessionLogger</span></span>
<span class="line"><span>session-store.ts          -- SessionStore: JSON file persistence for conversation sessions</span></span></code></pre></div><p><strong>Design patterns used:</strong></p><ul><li><strong>Facade</strong> -- <code>Session</code> hides Robota agent creation, tool registration, permission wiring, and hook execution behind a single <code>run()</code> method.</li><li><strong>Decorator</strong> -- Each tool is wrapped with a permission-checking proxy via <code>PermissionEnforcer.wrapTools()</code> before being registered with the Robota agent.</li><li><strong>Strategy (injected)</strong> -- Permission approval can be handled by a <code>TPermissionHandler</code> callback, an injected <code>promptForApproval</code> function, or denied by default.</li><li><strong>Composition</strong> -- Session delegates to PermissionEnforcer, ContextWindowTracker, and CompactionOrchestrator rather than implementing everything inline.</li><li><strong>Null Object</strong> -- When no <code>SessionStore</code> is provided, persistence is silently skipped.</li></ul><p><strong>Dependency direction:</strong></p><ul><li><code>@robota-sdk/agent-sessions</code> depends on <code>@robota-sdk/agent-core</code> only.</li><li>No dependency on <code>@robota-sdk/agent-tools</code> or <code>@robota-sdk/agent-provider-anthropic</code>.</li><li>Tool and provider assembly is the responsibility of the consuming layer (<code>agent-sdk</code>).</li></ul><h2 id="type-ownership" tabindex="-1">Type Ownership <a class="header-anchor" href="#type-ownership" aria-label="Permalink to &quot;Type Ownership&quot;">​</a></h2><p>Types owned by this package (SSOT):</p><table tabindex="0"><thead><tr><th>Type</th><th>Kind</th><th>File</th><th>Description</th></tr></thead><tbody><tr><td><code>ISessionOptions</code></td><td>Interface</td><td><code>session.ts</code></td><td>Constructor options for Session (tools, provider, systemMessage)</td></tr><tr><td><code>TPermissionHandler</code></td><td>Type</td><td><code>permission-enforcer.ts</code></td><td>Async callback <code>(toolName, toolArgs) =&gt; Promise&lt;TPermissionResult&gt;</code></td></tr><tr><td><code>TPermissionResult</code></td><td>Type</td><td><code>permission-enforcer.ts</code></td><td><code>boolean | &#39;allow-session&#39;</code></td></tr><tr><td><code>ITerminalOutput</code></td><td>Interface</td><td><code>permission-enforcer.ts</code></td><td>Terminal I/O abstraction (write, prompt, select, spinner)</td></tr><tr><td><code>ISpinner</code></td><td>Interface</td><td><code>permission-enforcer.ts</code></td><td>Spinner handle returned by <code>ITerminalOutput.spinner()</code></td></tr><tr><td><code>IPermissionEnforcerOptions</code></td><td>Interface</td><td><code>permission-enforcer.ts</code></td><td>Options for constructing PermissionEnforcer</td></tr><tr><td><code>ICompactionOptions</code></td><td>Interface</td><td><code>compaction-orchestrator.ts</code></td><td>Options for constructing CompactionOrchestrator</td></tr><tr><td><code>ISessionLogger</code></td><td>Interface</td><td><code>session-logger.ts</code></td><td>Pluggable session event logger interface</td></tr><tr><td><code>TSessionLogData</code></td><td>Type</td><td><code>session-logger.ts</code></td><td>Structured log event data (<code>Record&lt;string, string | number | boolean | object&gt;</code>)</td></tr><tr><td><code>ISessionRecord</code></td><td>Interface</td><td><code>session-store.ts</code></td><td>Persisted session record (id, cwd, timestamps, messages)</td></tr></tbody></table><p>Types consumed from other packages (not owned here):</p><table tabindex="0"><thead><tr><th>Type</th><th>Source</th></tr></thead><tbody><tr><td><code>Robota</code></td><td><code>@robota-sdk/agent-core</code></td></tr><tr><td><code>IAgentConfig</code></td><td><code>@robota-sdk/agent-core</code></td></tr><tr><td><code>IAIProvider</code></td><td><code>@robota-sdk/agent-core</code></td></tr><tr><td><code>IToolWithEventService</code></td><td><code>@robota-sdk/agent-core</code></td></tr><tr><td><code>TPermissionMode</code></td><td><code>@robota-sdk/agent-core</code></td></tr><tr><td><code>TToolArgs</code></td><td><code>@robota-sdk/agent-core</code></td></tr><tr><td><code>THooksConfig</code></td><td><code>@robota-sdk/agent-core</code></td></tr><tr><td><code>IHookInput</code></td><td><code>@robota-sdk/agent-core</code></td></tr><tr><td><code>evaluatePermission</code></td><td><code>@robota-sdk/agent-core</code></td></tr><tr><td><code>runHooks</code></td><td><code>@robota-sdk/agent-core</code></td></tr><tr><td><code>TRUST_TO_MODE</code></td><td><code>@robota-sdk/agent-core</code></td></tr><tr><td><code>TUniversalMessage</code></td><td><code>@robota-sdk/agent-core</code></td></tr></tbody></table><h2 id="public-api-surface" tabindex="-1">Public API Surface <a class="header-anchor" href="#public-api-surface" aria-label="Permalink to &quot;Public API Surface&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Export</th><th>Kind</th><th>Description</th></tr></thead><tbody><tr><td><code>Session</code></td><td>Class</td><td>Wraps Robota agent with permissions, hooks, streaming, and persistence</td></tr><tr><td><code>PermissionEnforcer</code></td><td>Class</td><td>Tool permission checking, hook execution, output truncation</td></tr><tr><td><code>ContextWindowTracker</code></td><td>Class</td><td>Token usage tracking and auto-compact threshold</td></tr><tr><td><code>CompactionOrchestrator</code></td><td>Class</td><td>Conversation compaction via LLM summary</td></tr><tr><td><code>SessionStore</code></td><td>Class</td><td>JSON file persistence for session records (<code>~/.robota/sessions/</code>)</td></tr><tr><td><code>FileSessionLogger</code></td><td>Class</td><td>JSONL file-based session event logger</td></tr><tr><td><code>SilentSessionLogger</code></td><td>Class</td><td>No-op session logger</td></tr><tr><td><code>ISessionOptions</code></td><td>Interface</td><td>Constructor options for Session</td></tr><tr><td><code>TPermissionHandler</code></td><td>Type</td><td>Custom permission approval callback</td></tr><tr><td><code>TPermissionResult</code></td><td>Type</td><td>Permission decision result</td></tr><tr><td><code>ITerminalOutput</code></td><td>Interface</td><td>Terminal I/O abstraction</td></tr><tr><td><code>ISpinner</code></td><td>Interface</td><td>Spinner handle</td></tr><tr><td><code>ISessionLogger</code></td><td>Interface</td><td>Pluggable session event logger interface</td></tr><tr><td><code>TSessionLogData</code></td><td>Type</td><td>Structured log event data</td></tr><tr><td><code>ISessionRecord</code></td><td>Interface</td><td>Persisted session record shape</td></tr><tr><td><code>IContextWindowState</code></td><td>Type</td><td>Context window usage state (re-exported from agent-core)</td></tr></tbody></table><h3 id="key-session-methods" tabindex="-1">Key Session Methods <a class="header-anchor" href="#key-session-methods" aria-label="Permalink to &quot;Key Session Methods&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Signature</th><th>Description</th></tr></thead><tbody><tr><td><code>run</code></td><td><code>(message: string) =&gt; Promise&lt;string&gt;</code></td><td>Send a message; returns AI response. Persists session if store exists.</td></tr><tr><td><code>getPermissionMode</code></td><td><code>() =&gt; TPermissionMode</code></td><td>Returns the active permission mode.</td></tr><tr><td><code>setPermissionMode</code></td><td><code>(mode: TPermissionMode) =&gt; void</code></td><td>Changes the permission mode for future tool calls.</td></tr><tr><td><code>getSessionId</code></td><td><code>() =&gt; string</code></td><td>Returns the stable session identifier.</td></tr><tr><td><code>getMessageCount</code></td><td><code>() =&gt; number</code></td><td>Returns the number of completed <code>run()</code> calls.</td></tr><tr><td><code>clearHistory</code></td><td><code>() =&gt; void</code></td><td>Clears the underlying Robota conversation history and resets token usage.</td></tr><tr><td><code>getHistory</code></td><td><code>() =&gt; TUniversalMessage[]</code></td><td>Returns the current conversation history.</td></tr><tr><td><code>getContextState</code></td><td><code>() =&gt; IContextWindowState</code></td><td>Returns real-time context window usage (tokens, percentage).</td></tr><tr><td><code>compact</code></td><td><code>(instructions?: string) =&gt; Promise&lt;void&gt;</code></td><td>Compresses conversation via LLM summary. System message is preserved across compaction (see below). Fires PreCompact/PostCompact hooks.</td></tr><tr><td><code>abort</code></td><td><code>() =&gt; void</code></td><td>Cancels the currently running <code>run()</code> call. No-op if not running.</td></tr><tr><td><code>isRunning</code></td><td><code>() =&gt; boolean</code></td><td>Returns true if a <code>run()</code> call is in progress.</td></tr><tr><td><code>getSessionAllowedTools</code></td><td><code>() =&gt; string[]</code></td><td>Returns tools that were session-approved (&quot;Allow always&quot;).</td></tr><tr><td><code>clearSessionAllowedTools</code></td><td><code>() =&gt; void</code></td><td>Clears all session-scoped allow rules.</td></tr></tbody></table><h3 id="key-sessionstore-methods" tabindex="-1">Key SessionStore Methods <a class="header-anchor" href="#key-sessionstore-methods" aria-label="Permalink to &quot;Key SessionStore Methods&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Method</th><th>Signature</th><th>Description</th></tr></thead><tbody><tr><td><code>save</code></td><td><code>(session: ISessionRecord) =&gt; void</code></td><td>Persist a session record to disk. Creates directory if needed.</td></tr><tr><td><code>load</code></td><td><code>(id: string) =&gt; ISessionRecord | undefined</code></td><td>Load a session by ID. Returns undefined if not found.</td></tr><tr><td><code>list</code></td><td><code>() =&gt; ISessionRecord[]</code></td><td>List all sessions, sorted by updatedAt descending.</td></tr><tr><td><code>delete</code></td><td><code>(id: string) =&gt; void</code></td><td>Delete a session file. No-ops if not found.</td></tr></tbody></table><h2 id="session-logging" tabindex="-1">Session Logging <a class="header-anchor" href="#session-logging" aria-label="Permalink to &quot;Session Logging&quot;">​</a></h2><p>The session log records structured events to a JSONL file for diagnostics and replay:</p><ul><li><strong><code>server_tool</code> event</strong> -- Recorded when a server-managed tool (e.g., web search) executes during streaming. Includes the tool name and query.</li><li><strong><code>pre_run</code> event</strong> -- Recorded at the start of each <code>run()</code> call. Includes the provider name and <code>webToolsEnabled</code> flag.</li><li><strong><code>assistant</code> event</strong> -- Recorded after each assistant response. Includes <code>historyStructure</code>: an array with per-message metadata (role, contentLength, hasToolCalls, toolCallNames, metadata).</li><li><strong><code>onServerToolUse</code> callback wiring</strong> -- When session logging is enabled, the <code>onServerToolUse</code> callback from the provider is automatically wired to emit <code>server_tool</code> log events.</li></ul><h2 id="extension-points" tabindex="-1">Extension Points <a class="header-anchor" href="#extension-points" aria-label="Permalink to &quot;Extension Points&quot;">​</a></h2><ol><li><p><strong><code>ISessionOptions.terminal</code></strong> (required) -- Inject an <code>ITerminalOutput</code> implementation for permission prompts and UI output. The consuming layer provides either a real terminal (CLI print mode) or an Ink-based no-op (TUI mode).</p></li><li><p><strong><code>ISessionOptions.tools</code></strong> -- Inject any set of <code>IToolWithEventService[]</code>. The consuming layer (agent-sdk) provides the default 8 tools + agent-tool.</p></li><li><p><strong><code>ISessionOptions.provider</code></strong> -- Inject any <code>IAIProvider</code>. The consuming layer (agent-sdk) creates the appropriate provider from config.</p></li><li><p><strong><code>ISessionOptions.systemMessage</code></strong> -- Inject the pre-built system prompt string. The consuming layer (agent-sdk) builds this from AGENTS.md, CLAUDE.md, tool descriptions, and trust level.</p></li><li><p><strong><code>ISessionOptions.permissionHandler</code></strong> -- Inject a custom permission approval callback (used by Ink-based UI to show approval prompts in React components).</p></li><li><p><strong><code>ISessionOptions.promptForApproval</code></strong> -- Alternative approval function that receives the terminal handle.</p></li><li><p><strong><code>ISessionOptions.onTextDelta</code></strong> -- Streaming callback for real-time text output to the UI.</p></li><li><p><strong><code>ISessionOptions.onToolExecution</code></strong> -- Callback for real-time tool execution events. Fires <code>{ type: &#39;start&#39;, toolName }</code> when a tool begins and <code>{ type: &#39;end&#39;, toolName, success }</code> when it completes. Wired through <code>PermissionEnforcer.wrapToolWithPermission()</code>.</p></li><li><p><strong><code>ISessionOptions.onCompact</code></strong> -- Callback invoked when compaction occurs (auto or manual), receives the generated summary string.</p></li><li><p><strong><code>ISessionOptions.compactInstructions</code></strong> -- Custom instructions for the compaction summary prompt (e.g., extracted from CLAUDE.md &quot;Compact Instructions&quot; section).</p></li><li><p><strong><code>SessionStore</code> constructor</strong> -- Accept a custom <code>baseDir</code> to redirect storage location (useful in tests).</p></li></ol><h2 id="compaction-behavior" tabindex="-1">Compaction Behavior <a class="header-anchor" href="#compaction-behavior" aria-label="Permalink to &quot;Compaction Behavior&quot;">​</a></h2><h3 id="system-message-preservation" tabindex="-1">System Message Preservation <a class="header-anchor" href="#system-message-preservation" aria-label="Permalink to &quot;System Message Preservation&quot;">​</a></h3><p>When <code>compact()</code> runs, the system message (project context: cwd, AGENTS.md, CLAUDE.md, tool descriptions, etc.) is <strong>preserved across compaction</strong>. The flow:</p><ol><li><strong>Exclude</strong> system messages from the summarization input — they are not summarized</li><li><strong>Clear</strong> conversation history</li><li><strong>Re-inject</strong> the original system message</li><li><strong>Inject</strong> the compact summary as an assistant message</li></ol><p>Post-compaction history:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[system]    Original system prompt (project context, rules, tool descriptions)</span></span>
<span class="line"><span>[assistant] [Context Summary] Summarized conversation...</span></span></code></pre></div><p>This ensures the AI retains project context (working directory, coding rules, available tools) after compaction. Without this, the AI loses awareness of the project environment.</p><h3 id="auto-compaction" tabindex="-1">Auto-Compaction <a class="header-anchor" href="#auto-compaction" aria-label="Permalink to &quot;Auto-Compaction&quot;">​</a></h3><p>Auto-compaction triggers at the <strong>start</strong> of <code>run()</code> (before processing the user message) when <code>ContextWindowTracker.shouldAutoCompact()</code> returns true. This prevents compaction from interfering with the current response stream.</p><h2 id="error-taxonomy" tabindex="-1">Error Taxonomy <a class="header-anchor" href="#error-taxonomy" aria-label="Permalink to &quot;Error Taxonomy&quot;">​</a></h2><p>This package does not define a custom error hierarchy. All errors are thrown as standard <code>Error</code> instances. Error scenarios include:</p><table tabindex="0"><thead><tr><th>Error Condition</th><th>Thrown By</th><th>Message Pattern</th></tr></thead><tbody><tr><td>Tool permission denied</td><td><code>PermissionEnforcer</code></td><td>Returns <code>IToolResult</code> with <code>&quot;Permission denied&quot;</code> (no throw)</td></tr><tr><td>Hook blocked tool</td><td><code>PermissionEnforcer</code></td><td>Returns <code>IToolResult</code> with <code>&quot;Blocked by hook: {reason}&quot;</code></td></tr><tr><td>Tool execution error</td><td><code>PermissionEnforcer</code></td><td>Returns <code>IToolResult</code> with error message (never throws)</td></tr></tbody></table><p>The permission wrapper deliberately catches all errors and returns them as <code>IToolResult</code> objects to avoid corrupting the conversation history with unmatched tool_use/tool_result pairs.</p><h3 id="session-run-error-recovery" tabindex="-1">Session.run() Error Recovery <a class="header-anchor" href="#session-run-error-recovery" aria-label="Permalink to &quot;Session.run() Error Recovery&quot;">​</a></h3><p>When <code>run()</code> encounters an error (e.g., from the execution loop or provider), the Session must:</p><ol><li><strong>Log the error</strong> — write an <code>error</code> event to the session logger with the error details</li><li><strong>Preserve history</strong> — conversation history up to the point of failure remains intact</li><li><strong>Remain usable</strong> — the session is not corrupted; the user can continue or retry</li><li><strong>Propagate the error</strong> — re-throw after logging so the caller can handle it (e.g., display an error message)</li></ol><h2 id="class-contract-registry" tabindex="-1">Class Contract Registry <a class="header-anchor" href="#class-contract-registry" aria-label="Permalink to &quot;Class Contract Registry&quot;">​</a></h2><h3 id="interface-implementations" tabindex="-1">Interface Implementations <a class="header-anchor" href="#interface-implementations" aria-label="Permalink to &quot;Interface Implementations&quot;">​</a></h3><p>No formal interface implementations. <code>Session</code>, <code>PermissionEnforcer</code>, <code>ContextWindowTracker</code>, <code>CompactionOrchestrator</code>, and <code>SessionStore</code> are standalone classes.</p><h3 id="inheritance-chains" tabindex="-1">Inheritance Chains <a class="header-anchor" href="#inheritance-chains" aria-label="Permalink to &quot;Inheritance Chains&quot;">​</a></h3><p>None. Classes are standalone.</p><h3 id="cross-package-port-consumers" tabindex="-1">Cross-Package Port Consumers <a class="header-anchor" href="#cross-package-port-consumers" aria-label="Permalink to &quot;Cross-Package Port Consumers&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Port (Owner)</th><th>Consumer Class</th><th>Location</th></tr></thead><tbody><tr><td><code>Robota</code> (agent-core)</td><td><code>Session</code></td><td><code>src/session.ts</code></td></tr><tr><td><code>IAIProvider</code> (agent-core)</td><td><code>Session</code></td><td><code>src/session.ts</code></td></tr><tr><td><code>evaluatePermission</code> (agent-core)</td><td><code>PermissionEnforcer</code></td><td><code>src/permission-enforcer.ts</code></td></tr><tr><td><code>runHooks</code> (agent-core)</td><td><code>PermissionEnforcer</code></td><td><code>src/permission-enforcer.ts</code></td></tr><tr><td><code>runHooks</code> (agent-core)</td><td><code>Session</code></td><td><code>src/session.ts</code> (PostCompact)</td></tr><tr><td><code>runHooks</code> (agent-core)</td><td><code>CompactionOrchestrator</code></td><td><code>src/compaction-orchestrator.ts</code></td></tr></tbody></table><h2 id="test-strategy" tabindex="-1">Test Strategy <a class="header-anchor" href="#test-strategy" aria-label="Permalink to &quot;Test Strategy&quot;">​</a></h2><h3 id="current-test-coverage" tabindex="-1">Current Test Coverage <a class="header-anchor" href="#current-test-coverage" aria-label="Permalink to &quot;Current Test Coverage&quot;">​</a></h3><ul><li><strong>Session system prompt delivery</strong> -- 6 tests verifying system prompt is passed to Robota at both top-level and defaultModel.</li></ul><h3 id="gaps" tabindex="-1">Gaps <a class="header-anchor" href="#gaps" aria-label="Permalink to &quot;Gaps&quot;">​</a></h3><ul><li><strong>Session</strong> -- <code>run()</code>, permission mode switching, hook integration, streaming callback wiring, and session persistence are untested.</li><li><strong>PermissionEnforcer</strong> -- <code>wrapTools()</code>, <code>checkPermission()</code>, session-scoped allow, tool truncation are untested.</li><li><strong>ContextWindowTracker</strong> -- <code>updateFromHistory()</code>, <code>shouldAutoCompact()</code>, metadata vs fallback estimation are untested.</li><li><strong>CompactionOrchestrator</strong> -- <code>compact()</code>, hook firing, prompt building are untested.</li><li><strong>SessionStore</strong> -- Covered by <code>agent-sdk/src/__tests__/session-store.test.ts</code> (12 tests: save/load/list/delete/directory creation).</li><li><strong>FileSessionLogger</strong> -- <code>log()</code>, file creation, JSONL formatting, error handling on read-only paths are untested.</li><li><strong>SilentSessionLogger</strong> -- No-op behavior untested (trivial, low priority).</li><li>All classes should be testable with mock <code>IAIProvider</code> and mock <code>ITerminalOutput</code> injections.</li></ul><h2 id="dependencies" tabindex="-1">Dependencies <a class="header-anchor" href="#dependencies" aria-label="Permalink to &quot;Dependencies&quot;">​</a></h2><h3 id="production-1" tabindex="-1">Production (1) <a class="header-anchor" href="#production-1" aria-label="Permalink to &quot;Production (1)&quot;">​</a></h3><ul><li><code>@robota-sdk/agent-core</code> -- Robota agent, permission system, hook system, core types</li></ul>`,59)]))}const u=t(d,[["render",n]]);export{g as __pageData,u as default};
